quickstart_example:
GET /api/1/companies HTTP/1.1
Host: api.freee.co.jp
Authorization: Bearer {access_token}
Accept: application/json

Response: {"companies":[{"id":123,"display_name":"テスト株式会社","role":"admin"}]}

GET /v1/employees HTTP/1.1
Host: api.smarthr.jp
Authorization: Bearer {access_token}
Accept: application/json

Response: {"data":[{"id":"abc123","last_name":"田中","first_name":"太郎","email":"tanaka@example.com"}],"next_cursor":"xyz789"}

POST /v2/rooms/123456/messages HTTP/1.1
Host: api.chatwork.com
X-ChatWorkToken: {your_token}
Content-Type: application/x-www-form-urlencoded

body=Hello+from+agent!

Response: {"message_id":"789"}

GET /k/v1/records.json?app=1&query=status%3D%22Open%22 HTTP/1.1
Host: example.cybozu.com
X-Cybozu-API-Token: {api_token}

Response: {"records":[{"$id":{"value":"1"},"title":{"value":"タスクA"}}],"totalCount":"42"}

POST /api/chat.postMessage HTTP/1.1
Host: slack.com
Authorization: Bearer xoxb-your-token
Content-Type: application/json

{"channel":"C01234567","text":"Hello from agent!"}

Response: {"ok":true,"channel":"C01234567","ts":"1234567890.123456"}

GET /admin/api/2024-10/products.json?limit=5 HTTP/1.1
Host: mystore.myshopify.com
X-Shopify-Access-Token: {access_token}

Response: {"products":[{"id":123,"title":"商品A","variants":[{"price":"1500.00"}]}]}

GET /api/v3/offices HTTP/1.1
Host: accounting.moneyforward.com
Authorization: Bearer {access_token}

Response: {"offices":[{"id":123,"display_name":"テスト事務所"}]}

GET /v1/documents?status=waiting HTTP/1.1
Host: api.cloudsign.jp
X-Api-Key: {api_key}
X-Client-Id: {client_id}

Response: {"documents":[{"id":"doc_123","title":"業務委託契約書","status":"waiting"}]}

GET /v8/bizcards?name=田中&limit=10 HTTP/1.1
Host: api.sansan.com
Authorization: Bearer {access_token}

Response: {"data":[{"id":"bc_123","personName":{"lastName":"田中","firstName":"太郎"},"companyName":"株式会社テスト","email":"tanaka@test.co.jp"}]}

POST /v2/bot/message/push HTTP/1.1
Host: api.line.me
Authorization: Bearer {channel_access_token}
Content-Type: application/json

{"to":"U1234567890abcdef","messages":[{"type":"text","text":"Hello!"}]}

Response: {}  (200 OK, empty body on success)

GET /crm/v3/objects/contacts?limit=10&properties=email,firstname,lastname HTTP/1.1
Host: api.hubapi.com
Authorization: Bearer {token}

Response: {"results":[{"id":"123","properties":{"email":"tanaka@example.com","firstname":"太郎","lastname":"田中"}}]}

POST /v1/databases/{database_id}/query HTTP/1.1
Host: api.notion.com
Authorization: Bearer {token}
Notion-Version: 2022-06-28
Content-Type: application/json

{"filter":{"property":"Status","select":{"equals":"Done"}}}

Response: {"results":[{"id":"page_123","properties":{"Name":{"title":[{"text":{"content":"タスクA"}}]}}}]}

GET /hr/api/v1/employees?company_id=123&limit=10 HTTP/1.1
Host: api.freee.co.jp
Authorization: Bearer {access_token}

Response: {"employees":[{"id":1,"last_name":"田中","first_name":"太郎","num":"EMP001","email":"tanaka@example.com"}]}

GET /api/v2/tickets?status=open&sort_by=created_at&sort_order=desc HTTP/1.1
Host: mycompany.zendesk.com
Authorization: Basic {base64(email/token:api_token)}
Accept: application/json

Response: {"tickets":[{"id":123,"subject":"ログインできない","status":"open","requester_id":456}]}

POST /2010-04-01/Accounts/{AccountSid}/Messages.json HTTP/1.1
Host: api.twilio.com
Authorization: Basic {base64(AccountSid:AuthToken)}
Content-Type: application/x-www-form-urlencoded

To=%2B819012345678&From=%2B815012345678&Body=Hello+from+agent!

Response: {"sid":"SM123...","status":"queued"}

GET /v2/locations HTTP/1.1
Host: connect.squareup.com
Authorization: Bearer {access_token}
Accept: application/json

Response: {"locations":[{"id":"LOC123","name":"渋谷店","address":{"country":"JP"},"currency":"JPY"}]}

POST /v1/text-to-speech/{voice_id}
xi-api-key: {api_key}
Content-Type: application/json

{"text":"Hello world","model_id":"eleven_multilingual_v2"}

Response: audio/mpeg binary

GET /v3/company/{realmId}/query?query=SELECT * FROM Invoice WHERE TotalAmt > '100.00'
Authorization: Bearer {access_token}
Accept: application/json

GET /apps
Authorization: Bearer {api_key}
Accept: application/vnd.heroku+json; version=3

POST /api/2.0/sql/statements
Authorization: Bearer {token}

{"warehouse_id":"{id}","statement":"SELECT * FROM catalog.schema.table LIMIT 10"}

aws lambda invoke --function-name my-function --payload '{"key":"value"}' output.json

OR via SDK:
const { LambdaClient, InvokeCommand } = require('@aws-sdk/client-lambda');
const client = new LambdaClient({ region: 'ap-northeast-1' });
await client.send(new InvokeCommand({ FunctionName: 'my-func', Payload: JSON.stringify({key:'val'}) }));

// Using @google-cloud/storage SDK
const {Storage} = require('@google-cloud/storage');
const storage = new Storage(); // ADC auto-detects credentials
const [files] = await storage.bucket('my-bucket').getFiles();
console.log(files.map(f => f.name));

GET /client/v4/zones
Authorization: Bearer {api_token}
Content-Type: application/json

Response: {"success":true,"result":[{"id":"...","name":"example.com",...}]}

POST /api/1.0/tasks
Authorization: Bearer {token}
Content-Type: application/json

{"data":{"workspace":"{workspace_gid}","name":"New task","projects":["{project_gid}"]}}

POST /v1/exposed/{action_id}/execute/
Authorization: Bearer {api_key}
Content-Type: application/json

{"instructions":"Send a Slack message to #general saying hello"}

